def narrative_btn(pid, suffix=''):
  pid2 = pid.replace('-','') + suffix
  data = NARRATIVES.get(pid, {'intro': '深度叙事即将呈现。', 'items': []})
  items_html = ''
  for item in data.get('items', []):
    if len(item) == 4:
      cn_name, en_name, tag, text = item
      subtitle = f'<span class="col-tag">典藏 · {tag}</span><span class="col-en">{en_name}</span>'
    else:
      en_name, cn_name, text = item
      subtitle = f'<span style="color:var(--gold);font-weight:400;letter-spacing:.06em">{en_name}</span>'
    name_for_notes = cn_name if len(item) == 4 else en_name
    notes_html = ''
    product_notes = PRODUCT_NOTES.get(name_for_notes, [])
    if product_notes:
      chips = ''
      for note_name, note_desc in product_notes:
        chips += f'<span class="note-chip"><span class="note-chip-name">{note_name}</span><span class="note-chip-tip">{note_desc}</span></span>'
      notes_html = f'<div class="note-chips">{chips}</div>'
    items_html += f'''<div style="margin-bottom:2.2rem">
<h4 style="font-family:'Cormorant Garamond',serif;font-size:1.1rem;font-weight:400;color:var(--ink);margin-bottom:.1rem;letter-spacing:.08em">{cn_name}</h4>
<p style="font-family:'Noto Serif SC',serif;font-size:.66rem;color:var(--gold-d);letter-spacing:.2em;margin-bottom:.5rem">{subtitle}</p>
<p style="font-family:'Noto Serif SC',serif;font-size:.8rem;font-weight:300;color:var(--ink2);line-height:2.4;letter-spacing:.04em;max-width:680px;margin:0 auto;text-align:justify">{text}</p>
{notes_html}
</div>'''
  return f'''<div style="text-align:center;margin:1rem 0 2rem">
<button class="narr-btn" data-target="{pid2}">展开叙事</button>
<div class="narr-body" id="{pid2}" style="max-width:1200px;margin:0 auto;padding:2rem;text-align:center">
<div class="glass-panel" style="padding:3rem 2.5rem;font-family:Noto Serif SC,serif;font-size:.9rem;font-weight:300;color:var(--ink3);line-height:2.5">
<p style="font-family:'Noto Serif SC',serif;font-size:.92rem;font-weight:300;color:var(--ink2);line-height:2.6;max-width:640px;margin:0 auto 2.5rem;letter-spacing:.04em">{data['intro']}</p>
<div style="width:36px;height:1px;background:var(--gold-d);opacity:.2;margin:0 auto 2.5rem"></div>
{items_html}
</div></div></div>'''

